import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { Users, Mail, Phone, MapPin, Award, BookOpen, Calendar, Linkedin, Twitter, Github, GraduationCap, Shield, Star, Clock, Building, User, X, UserCheck, Briefcase, Settings } from 'lucide-react';

// Import Swiper React components
import { Swiper, SwiperSlide } from 'swiper/react';

// Import Swiper styles
import 'swiper/css';
import 'swiper/css/parallax';
import 'swiper/css/pagination';
import 'swiper/css/navigation';

// Import required modules - Updated for Swiper v9
import { Parallax, Pagination, Navigation, Autoplay } from 'swiper';

// Import custom styles
import '../styles/Swiper-Customs.css';

// Import teacher images from assets
import teacher1 from '../assets/teachers/中野先生.jpg';
import teacher2 from '../assets/teachers/丸山先生.jpg';
import teacher3 from '../assets/teachers/亀山先生.jpg';
import teacher4 from '../assets/teachers/京先生.jpg';
import teacher5 from '../assets/teachers/坂口先生.jpg';
import teacher6 from '../assets/teachers/大瀧先生.jpg';

const Team = () => {
    const { t } = useTranslation();
    const [isHeroVisible, setIsHeroVisible] = useState(false);
    const heroRef = useRef(null);

    useEffect(() => {
        setIsHeroVisible(true);
        createHeroAnimatedElements();
        
        const sections = document.querySelectorAll('.about-section');
        
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });
        
        sections.forEach(section => {
            observer.observe(section);
        });
        
        return () => {
            sections.forEach(section => {
                observer.unobserve(section);
            });
            
            const elements = document.querySelector('.about-hero-elements');
            if (elements) {
                while (elements.firstChild) {
                    elements.removeChild(elements.firstChild);
                }
            }
        };
    }, []);

    const createHeroAnimatedElements = () => {
        const container = document.querySelector('.about-hero-elements');
        if (!container) return;
        
        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }
        
        for (let i = 0; i < 20; i++) {
            const shape = document.createElement('div');
            shape.className = 'about-shape';
            
            const shapes = ['circle', 'triangle', 'square', 'plus'];
            const shapeType = shapes[Math.floor(Math.random() * shapes.length)];
            shape.classList.add(`shape-${shapeType}`);
            
            const x = Math.random() * 100;
            const y = Math.random() * 100;
            const size = Math.random() * 30 + 10;
            const opacity = Math.random() * 0.5 + 0.1;
            const animationDelay = Math.random() * 5;
            const animationDuration = Math.random() * 20 + 10;
            
            shape.style.left = `${x}%`;
            shape.style.top = `${y}%`;
            shape.style.width = `${size}px`;
            shape.style.height = `${size}px`;
            shape.style.opacity = opacity;
            shape.style.animationDelay = `${animationDelay}s`;
            shape.style.animationDuration = `${animationDuration}s`;
            
            container.appendChild(shape);
        }
        
        const icons = ['people', 'school', 'groups', 'emoji_people', 'psychology', 'supervisor_account'];
        for (let i = 0; i < 6; i++) {
            const iconWrapper = document.createElement('div');
            iconWrapper.className = 'about-hero-icon';
            
            const x = 10 + (Math.random() * 80);
            const y = 10 + (Math.random() * 80);
            const delay = Math.random() * 5;
            
            iconWrapper.style.left = `${x}%`;
            iconWrapper.style.top = `${y}%`;
            iconWrapper.style.animationDelay = `${delay}s`;
            
            const icon = document.createElement('span');
            icon.className = 'material-icons';
            icon.textContent = icons[i % icons.length];
            
            iconWrapper.appendChild(icon);
            container.appendChild(iconWrapper);
        }
    };

    // Combined all team members data
    const allTeamMembers = [
        // Teachers
        {
            id: 1,
            name: '中野先生 (Nakano-sensei)',
            title: 'Senior Web Development Instructor',
            department: 'Computer Science',
            image: teacher1,
            email: 'nakano@forumacademy.edu',
            phone: '+81 (03) 1234-5678',
            location: 'Tokyo, Japan',
            experience: '8 years',
            specializations: ['React.js', 'Node.js', 'Full-Stack Development', 'UI/UX Design'],
            bio: '中野先生は8年以上のWeb開発経験を持つ情熱的な教育者です。モダンなJavaScriptフレームワークを専門とし、フォーラムアカデミーに参加する前は大手テック企業で働いていました。',
            education: ['Ph.D. Computer Science - Tokyo University', 'M.S. Software Engineering - Waseda University'],
            achievements: ['Best Instructor Award 2023', '50+ Students Placed in Top Companies'],
            social: {
                linkedin: 'https://linkedin.com/in/nakano-sensei',
                twitter: 'https://twitter.com/nakano-sensei',
                github: 'https://github.com/nakano-sensei'
            }
        },
        {
            id: 2,
            name: '丸山先生 (Maruyama-sensei)',
            title: 'データサイエンス主任講師 (Data Science Lead Instructor)',
            department: 'Data Science',
            image: teacher2,
            email: 'maruyama@forumacademy.edu',
            phone: '+81 (03) 2345-6789',
            location: 'Tokyo, Japan',
            experience: '12 years',
            specializations: ['Machine Learning', 'Python', 'Data Analytics', 'AI Research'],
            bio: '趣味：読書・テニス、メッセージ：「データの力で未来を切り開きましょう！一緒に学び成長していきましょう。」',
            education: ['Ph.D. Computer Science - Tokyo University', 'M.S. Mathematics - Waseda University'],
            achievements: ['Research Excellence Award', 'Published 25+ Research Papers'],
            social: {
                linkedin: 'https://linkedin.com/in/maruyama-sensei',
                github: 'https://github.com/maruyama-sensei'
            }
        },
        {
            id: 3,
            name: '亀山先生 (Kameyama-sensei)',
            title: 'サイバーセキュリティ講師 (Cybersecurity Instructor)',
            department: 'Cybersecurity',
            image: teacher3,
            email: 'kameyama@forumacademy.edu',
            phone: '+81 (03) 3456-7890',
            location: 'Tokyo, Japan',
            experience: '6 years',
            specializations: ['Network Security', 'Ethical Hacking', 'Penetration Testing', 'Security Protocols'],
            bio: '趣味：ゲーム・プログラミング、メッセージ：「セキュリティの世界は奥が深いです。一緒に探求していきましょう！」',
            education: ['M.S. Cybersecurity - Tokyo Institute of Technology', 'B.S. Computer Science - Keio University'],
            achievements: ['CISSP Certified', 'CEH Certified', 'Security Consultant of the Year 2022'],
            social: {
                linkedin: 'https://linkedin.com/in/kameyama-sensei',
                twitter: 'https://twitter.com/kameyama-sensei'
            }
        },
        {
            id: 4,
            name: 'Dr. Ahmed Hassan',
            title: 'Mobile Development Instructor',
            department: 'Mobile Technology',
            image: teacher4,
            email: 'ahmed.hassan@forumacademy.edu',
            phone: '+1 (555) 456-7890',
            location: 'Los Angeles, CA',
            experience: '9 years',
            specializations: ['React Native', 'Flutter', 'iOS Development', 'Android Development'],
            bio: 'Dr. Hassan is an expert in mobile application development with extensive experience in cross-platform solutions.',
            education: ['Ph.D. Computer Engineering - UCLA', 'M.S. Mobile Computing - USC'],
            achievements: ['Mobile Innovation Award 2022', '100+ Apps Published'],
        },
        {
            id: 5,
            name: 'Emily Watson',
            title: 'Cloud Architecture Instructor',
            department: 'Cloud Computing',
            image: teacher5,
            email: 'emily.watson@forumacademy.edu',
            phone: '+1 (555) 567-8901',
            location: 'Seattle, WA',
            experience: '7 years',
            specializations: ['AWS', 'Azure', 'Docker', 'Kubernetes', 'DevOps'],
            bio: 'Emily specializes in cloud infrastructure and DevOps practices, helping students master modern deployment strategies.',
            education: ['M.S. Cloud Computing - University of Washington', 'B.S. Information Systems - WSU'],
            achievements: ['AWS Certified Solutions Architect', 'Cloud Excellence Award 2023'],
            social: {
                linkedin: 'https://linkedin.com/in/emilywatson',
                github: 'https://github.com/emilywatson'
            }
        },
        {
            id: 6,
            name: 'Dr. Robert Kim',
            title: 'AI & Machine Learning Instructor',
            department: 'Artificial Intelligence',
            image: teacher6,
            email: 'robert.kim@forumacademy.edu',
            phone: '+1 (555) 678-9012',
            location: 'Boston, MA',
            experience: '11 years',
            specializations: ['Deep Learning', 'Neural Networks', 'Computer Vision', 'Natural Language Processing'],
            bio: 'Dr. Kim is a renowned AI researcher and educator, leading breakthrough projects in machine learning applications.',
            education: ['Ph.D. Artificial Intelligence - MIT', 'M.S. Computer Science - Harvard'],
            achievements: ['AI Research Pioneer Award', 'Published 40+ Research Papers'],
            social: {
                linkedin: 'https://linkedin.com/in/robertkim',
                github: 'https://github.com/robertkim'
            }
        },
        // Management Team
        {
            id: 7,
            name: 'Dr. Maria Santos',
            title: 'Principal / Director',
            department: 'Management',
            image: 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'maria.santos@forumacademy.edu',
            phone: '+1 (555) 123-0001',
            location: 'New York, NY',
            experience: '20 years',
            specializations: ['Educational Leadership', 'Strategic Planning', 'Academic Excellence', 'Institutional Management'],
            bio: 'Dr. Santos leads Forum Academy with a vision for innovative education and student success. She has transformed multiple educational institutions through strategic leadership.',
            education: ['Ed.D. Educational Leadership - Columbia University', 'M.Ed. Administration - NYU'],
            achievements: ['Educational Excellence Award 2023', 'Transformed 5+ Educational Institutions'],
            social: {
                linkedin: 'https://linkedin.com/in/mariasantos'
            }
        },
        {
            id: 8,
            name: 'James Wilson',
            title: 'Vice Principal / Academic Coordinator',
            department: 'Academic Management',
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'james.wilson@forumacademy.edu',
            phone: '+1 (555) 123-0002',
            location: 'Boston, MA',
            experience: '15 years',
            specializations: ['Academic Coordination', 'Curriculum Oversight', 'Faculty Management', 'Quality Assurance'],
            bio: 'James ensures academic excellence and coordinates all educational programs at Forum Academy.',
            education: ['M.Ed. Curriculum & Instruction - Harvard', 'B.A. Education - Boston University'],
            achievements: ['Academic Innovation Award', 'Led Curriculum Modernization'],
            social: {
                linkedin: 'https://linkedin.com/in/jameswilson'
            }
        },
        // Career Support Team
        {
            id: 9,
            name: 'Sarah Mitchell',
            title: 'Career Services Director',
            department: 'Career Support',
            image: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'sarah.mitchell@forumacademy.edu',
            phone: '+1 (555) 123-0003',
            location: 'San Francisco, CA',
            experience: '12 years',
            specializations: ['Career Counseling', 'Industry Partnerships', 'Job Placement', 'Professional Development'],
            bio: 'Sarah connects students with career opportunities and builds relationships with industry partners.',
            education: ['M.S. Career Counseling - UCSF', 'B.A. Psychology - Stanford'],
            achievements: ['95% Job Placement Rate', '200+ Industry Partnerships'],
            social: {
                linkedin: 'https://linkedin.com/in/sarahmitchell'
            }
        },
        {
            id: 10,
            name: 'Michael Rodriguez',
            title: 'Student Support Specialist',
            department: 'Student Support',
            image: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'michael.rodriguez@forumacademy.edu',
            phone: '+1 (555) 123-0004',
            location: 'Los Angeles, CA',
            experience: '8 years',
            specializations: ['Academic Support', 'Mental Health', 'Student Advocacy', 'Crisis Intervention'],
            bio: 'Michael provides comprehensive support to help students overcome challenges and achieve their goals.',
            education: ['M.S.W. Social Work - UCLA', 'B.A. Psychology - USC'],
            achievements: ['Student Advocate Award', 'Mental Health First Aid Certified'],
            social: {
                linkedin: 'https://linkedin.com/in/michaelrodriguez'
            }
        },
        // Admin Team
        {
            id: 11,
            name: 'Robert Johnson',
            title: 'Registrar',
            department: 'Administrative Office',
            image: 'https://images.unsplash.com/photo-1560250097-0b93528c311a?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'robert.johnson@forumacademy.edu',
            phone: '+1 (555) 123-0006',
            location: 'Austin, TX',
            experience: '14 years',
            specializations: ['Student Records', 'Enrollment Management', 'Academic Policies', 'Compliance'],
            bio: 'Robert manages all student records and ensures compliance with academic policies and regulations.',
            education: ['M.Ed. Higher Education Administration - UT Austin', 'B.A. Business Administration - Texas A&M'],
            achievements: ['Compliance Excellence Award', 'Digitized Student Records System'],
            social: {
                linkedin: 'https://linkedin.com/in/robertjohnson'
            }
        },
        // Tech Support Team
        {
            id: 12,
            name: 'David Park',
            title: 'IT Director',
            department: 'IT Support',
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'david.park@forumacademy.edu',
            phone: '+1 (555) 123-0008',
            location: 'Seattle, WA',
            experience: '16 years',
            specializations: ['Network Administration', 'Cybersecurity', 'Cloud Infrastructure', 'System Integration'],
            bio: 'David oversees all IT operations and ensures secure, reliable technology infrastructure for the academy.',
            education: ['M.S. Information Technology - University of Washington', 'B.S. Computer Science - UW'],
            achievements: ['Zero Security Breaches Record', 'Cloud Migration Excellence Award'],
            social: {
                linkedin: 'https://linkedin.com/in/davidpark',
                github: 'https://github.com/davidpark'
            }
        }
    ];

    // Swiper Slide Component
    const SwiperSlideCard = ({ member }) => (
        <div className="w-full h-full bg-white rounded-3xl shadow-xl overflow-hidden">
            {/* Parallax background */}
            <div
                className="absolute inset-0 bg-gradient-to-br from-blue-100 via-purple-100 to-pink-100"
                data-swiper-parallax="-23%"
            ></div>
            
            <div className="relative z-10 p-8 h-full flex flex-col">
                {/* Image with parallax */}
                <div 
                    className="flex justify-center mb-6"
                    data-swiper-parallax="-100"
                >
                    <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-white shadow-lg">
                        <img
                            src={member.image}
                            alt={member.name}
                            className="w-full h-full object-cover"
                            onError={(e) => {
                                e.target.src = 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80';
                            }}
                        />
                    </div>
                </div>

                {/* Name and Title with parallax */}
                <div 
                    className="text-center mb-6"
                    data-swiper-parallax="-200"
                >
                    <h3 className="text-xl font-bold text-gray-900 mb-2">
                        {member.name}
                    </h3>
                    <p className="text-blue-600 font-semibold text-sm mb-2">{member.title}</p>
                    <div className="flex items-center justify-center text-gray-500 text-sm">
                        <Building className="w-4 h-4 mr-1" />
                        {member.department}
                    </div>
                </div>

                {/* Quick Info with parallax */}
                <div 
                    className="space-y-3 mb-6"
                    data-swiper-parallax="-300"
                    data-swiper-parallax-duration="600"
                >
                    <div className="flex items-center text-gray-600 text-sm">
                        <MapPin className="w-4 h-4 mr-3 text-blue-500" />
                        {member.location}
                    </div>
                    <div className="flex items-center text-gray-600 text-sm">
                        <Clock className="w-4 h-4 mr-3 text-purple-500" />
                        {member.experience} experience
                    </div>
                    <div className="flex items-center text-gray-600 text-sm">
                        <Mail className="w-4 h-4 mr-3 text-green-500" />
                        <a href={`mailto:${member.email}`} className="hover:text-blue-600 transition-colors duration-300">
                            {member.email}
                        </a>
                    </div>
                </div>

                {/* Specializations with opacity parallax */}
                <div 
                    className="mb-6"
                    data-swiper-parallax-opacity="0.5"
                >
                    <h4 className="text-sm font-semibold text-gray-700 mb-3 flex items-center">
                        <Star className="w-4 h-4 mr-2 text-yellow-500" />
                        Specializations
                    </h4>
                    <div className="flex flex-wrap gap-2">
                        {member.specializations.slice(0, 4).map((spec, index) => (
                            <span
                                key={index}
                                className="px-3 py-1 bg-gradient-to-r from-blue-100 to-purple-100 text-blue-700 rounded-full text-xs font-medium border border-blue-200"
                            >
                                {spec}
                            </span>
                        ))}
                        {member.specializations.length > 4 && (
                            <span className="px-3 py-1 bg-gray-100 text-gray-600 rounded-full text-xs font-medium">
                                +{member.specializations.length - 4}
                            </span>
                        )}
                    </div>
                </div>

                {/* Bio with scale parallax */}
                <div 
                    className="mb-6 flex-grow"
                    data-swiper-parallax-scale="0.15"
                >
                    <p className="text-gray-600 text-sm leading-relaxed line-clamp-4">
                        {member.bio.length > 150 ? `${member.bio.substring(0, 150)}...` : member.bio}
                    </p>
                </div>

                {/* Social Links */}
                <div className="flex justify-center space-x-3 mt-auto">
                    {member.social?.linkedin && (
                        <a
                            href={member.social.linkedin}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="p-3 bg-blue-100 text-blue-600 rounded-full hover:bg-blue-200 transition-colors duration-300 transform hover:scale-110"
                        >
                            <Linkedin className="w-5 h-5" />
                        </a>
                    )}
                    {member.social?.github && (
                        <a
                            href={member.social.github}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="p-3 bg-gray-100 text-gray-600 rounded-full hover:bg-gray-800 hover:text-white transition-colors duration-300 transform hover:scale-110"
                        >
                            <Github className="w-5 h-5" />
                        </a>
                    )}
                    {member.social?.twitter && (
                        <a
                            href={member.social.twitter}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="p-3 bg-blue-50 text-blue-500 rounded-full hover:bg-blue-100 transition-colors duration-300 transform hover:scale-110"
                        >
                            <Twitter className="w-5 h-5" />
                        </a>
                    )}
                </div>
            </div>
        </div>
    );

    return (
        <div className="about-page">
            {/* Hero Section - Keep existing */}
            <section 
                ref={heroRef}
                className={`min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50 flex items-center ${isHeroVisible ? 'visible' : ''}`}
            >
                <div className="about-hero-elements"></div>
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center py-20">
                        <div className="inline-flex items-center bg-blue-100 text-blue-600 px-4 py-2 rounded-full text-sm font-semibold uppercase tracking-wider mb-8">
                            <span className="material-icons mr-2">people</span>
                            {t('Hello, Welcome to Our Faculty') || 'Hello, Welcome to Our Faculty'}
                        </div>
                        
                        <h1 className="text-5xl md:text-6xl lg:text-7xl font-black text-gray-900 leading-tight mb-8">
                            {t('Meet Our Amazing') || 'Meet Our Amazing'} <br />
                            <span className="bg-gradient-to-r from-blue-600 via-purple-600 to-indigo-600 bg-clip-text text-transparent block md:inline">
                                {t('Faculty Team') || 'Faculty Team'}
                            </span>
                        </h1>
                        
                        <p className="text-xl md:text-2xl text-gray-600 leading-relaxed max-w-4xl mx-auto mb-12 font-light">
                            {t('Hello! Welcome to our dedicated team of passionate educators and professionals who are committed to transforming your learning journey. Our faculty brings together industry expertise and academic excellence to provide you with world-class education.') || 'Hello! Welcome to our dedicated team of passionate educators and professionals who are committed to transforming your learning journey. Our faculty brings together industry expertise and academic excellence to provide you with world-class education.'}
                        </p>
                        
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-12">
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-blue-600 transition-colors duration-300">
                                    50+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Expert Faculty Members') || 'Expert Faculty Members'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-purple-600 transition-colors duration-300">
                                    15+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Years Combined Experience') || 'Years Combined Experience'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-green-600 transition-colors duration-300">
                                    95%
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Student Satisfaction Rate') || 'Student Satisfaction Rate'}
                                </div>
                            </div>
                            <div className="text-center group">
                                <div className="text-4xl md:text-5xl font-bold text-gray-900 mb-2 group-hover:text-indigo-600 transition-colors duration-300">
                                    100+
                                </div>
                                <div className="text-sm md:text-base text-gray-600 font-medium uppercase tracking-wide">
                                    {t('Professional Certifications') || 'Professional Certifications'}
                                </div>
                            </div>
                        </div>
                        
                        <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
                            <a 
                                href="#team-members" 
                                className="inline-flex items-center px-8 py-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white font-semibold text-lg rounded-full shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300 hover:from-blue-700 hover:to-purple-700"
                            >
                                <span className="material-icons mr-2">groups</span>
                                {t('Explore Our Faculty') || 'Explore Our Faculty'}
                            </a>
                            <a 
                                href="/contact" 
                                className="inline-flex items-center px-8 py-4 border-2 border-gray-800 text-gray-800 font-semibold text-lg rounded-full hover:bg-gray-800 hover:text-white transition-all duration-300 hover:shadow-lg transform hover:scale-105"
                            >
                                <span className="material-icons mr-2">work</span>
                                {t('Join Our Team') || 'Join Our Team'}
                            </a>
                        </div>
                    </div>
                </div>
            </section>

            {/* Team Section with Swiper */}
            <section id="team-members" className="py-20 bg-gradient-to-br from-gray-50 to-blue-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    {/* Section Header */}
                    <div className="text-center mb-16">
                        <h2 className="text-4xl font-bold text-gray-900 mb-4">
                            Our <span className="text-blue-600">Faculty Teams</span>
                        </h2>
                        <p className="text-lg text-gray-600 max-w-3xl mx-auto">
                            Our dedicated team of professionals brings years of industry experience and passion for education to help you succeed in your learning journey.
                        </p>
                    </div>

                    {/* Swiper Carousel */}
                    <div className="swiper-container">
                        <Swiper
                            speed={600}
                            parallax={true}
                            pagination={{
                                clickable: true,
                                dynamicBullets: true,
                            }}
                            navigation={true}
                            autoplay={{
                                delay: 5000,
                                disableOnInteraction: false,
                            }}
                            modules={[Parallax, Pagination, Navigation, Autoplay]}
                            spaceBetween={30}
                            slidesPerView={1}
                            breakpoints={{
                                640: {
                                    slidesPerView: 2,
                                },
                                1024: {
                                    slidesPerView: 3,
                                },
                            }}
                            className="team-swiper"
                        >
                            {/* Parallax background element */}
                            <div
                                className="absolute inset-0 bg-gradient-to-br from-blue-200 via-purple-200 to-pink-200 opacity-30"
                                data-swiper-parallax="-23%"
                            ></div>
                            
                            {allTeamMembers.map((member) => (
                                <SwiperSlide key={member.id} className="h-auto">
                                    <div className="h-full min-h-[600px]">
                                        <SwiperSlideCard member={member} />
                                    </div>
                                </SwiperSlide>
                            ))}
                        </Swiper>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default Team;
